# Allowed working directories (jobs must run within these)
ALLOWED_WORK_DIRS = [
    "/opt/jobs/workspace",
    "/tmp/batch_jobs",
]


def validate_command(command_parts: list[str]) -> tuple[bool, str]:
    """Validate a command against the allowlist and security rules."""
    if not command_parts:
        return False, "Empty command"

    executable = os.path.basename(command_parts[0])

    # Check if command is in allowlist
    if executable not in ALLOWED_COMMANDS:
        return False, f"Command '{executable}' is not in the allowlist. Allowed: {list(ALLOWED_COMMANDS.keys())}"

    config = ALLOWED_COMMANDS[executable]

    # Check argument count
    args = command_parts[1:]
    if len(args) > config["max_args"]:
        return False, f"Too many arguments ({len(args)}). Max allowed: {config['max_args']}"

    # Check each argument against dangerous patterns
    full_command_str = " ".join(command_parts)
    for pattern in DANGEROUS_PATTERNS:
        if re.search(pattern, full_command_str):
            return False, f"Dangerous pattern detected in command: {pattern}"

    # Validate each argument against allowed pattern
    for arg in args:
        if not re.match(config["allowed_args_pattern"], arg):
            return False, f"Argument '{arg}' does not match allowed pattern for '{executable}'"

    return True, "OK"


def validate_working_directory(work_dir: str) -> tuple[bool, str]:
    """Validate that the working directory is within allowed paths."""
    if not work_dir:
        return True, "OK"  # Will use default

    resolved = os.path.realpath(work_dir)
    for allowed_dir in ALLOWED_WORK_DIRS:
        if resolved.startswith(os.path.realpath(allowed_dir)):
            return True, "OK"

    return False, f"Working directory '{work_dir}' is not within allowed paths: {ALLOWED_WORK_DIRS}"


def parse_job_message(body: bytes) -> dict:
    """Parse and validate the job message structure."""
    try:
        message = json.loads(body)
    except json.JSONDecodeError as e:
        raise ValueError(f"Invalid JSON in message: {e}")

    if not isinstance(message, dict):
        raise ValueError("Message must be a JSON object")

    if "command" not in message:
        raise ValueError("Message must contain a 'command' field")

    if not isinstance(message["command"], list):
        # If command is a string, parse it safely with shlex
        if isinstance(message["command"], str):
            try:
                message["command"] = shlex.split(message["command"])
            except ValueError as e:
                raise ValueError(f"Failed to parse command string: {e}")
        else:
            raise ValueError("'command' must be a string or list of strings")

    # Ensure all parts are strings
    message["command"] = [str(part) for part in message["command"]]

    return message


def execute_job(message: dict) -> dict:
    """Execute a validated job command securely."""
    command_parts = message["command"]
    work_dir = message.get("working_directory", ALLOWED_WORK_DIRS[0])
    timeout = min(message.get("timeout", 300), 600)  # Max 10 minutes

    # Validate command
    is_valid, reason = validate_command(command_parts)
    if not is_valid:
        return {"success": False, "error": f"Command validation failed: {reason}"}

    # Validate working directory
    is_valid, reason = validate_working_directory(work_dir)
    if not is_valid:
        return {"success": False, "error": f"Working directory validation failed: {reason}"}

    # Ensure working directory exists
    if not os.path.isdir(work_dir):
        return {"success": False, "error": f"Working directory does not exist: {work_dir}"}

    logger.info("Executing validated command: %s in %s", command_parts, work_dir)

    try:
        # Execute with subprocess.run using a list (no shell=True!)
        # This avoids shell injection entirely since we pass a list of args
        result = subprocess.run(
            command_parts,
            shell=False,          # NEVER use shell=True with external input
            capture_output=True,
            text=True,
            timeout=timeout,
            cwd=work_dir,
            env={                 # Minimal, controlled environment
                "PATH": "/usr/local/bin:/usr/bin:/bin",
                "HOME": work_dir,
                "LANG": "C.UTF-8",
            },
        )

        return {
            "success": result.returncode == 0,
            "returncode": result.returncode,
            "stdout": result.stdout[:10000],  # Limit output size
            "stderr": result.stderr[:10000],
        }

    except subprocess.TimeoutExpired:
        return {"success": False, "error": f"Command timed out after {timeout}s"}
    except FileNotFoundError:
        return {"success": False, "error": f"Command not found: {command_parts[0]}"}
    except PermissionError:
        return {"success": False, "error": "Permission denied executing command"}
    except Exception as e:
        return {"success": False, "error": f"Execution error: {type(e).__name__}: {e}"}


def on_message(channel, method, properties, body):
    """Callback for processing messages from the queue."""
    job_id = properties.correlation_id or "unknown"
    logger.info("Received job %s", job_id)

    try:
        # Parse and validate message
        message = parse_job_message(body)
        logger.info("Job %s: command=%s", job_id, message.get("command"))

        # Execute the job
        result = execute_job(message)

        if result["success"]:
            logger.info("Job %s completed successfully", job_id)
        else:
            logger.warning("Job %s failed: %s", job_id, result.get("error", "unknown error"))

        # If there's a reply_to queue, send the result back
        if properties.reply_to:
            channel.basic_publish(
                exchange="",
                routing_key=properties.reply_to,
                properties=pika.BasicProperties(
                    correlation_id=job_id,
                    content_type="application/json",
                ),
                body=json.dumps(result),
            )

        # Acknowledge the message
        channel.basic_ack(delivery_tag=method.delivery_tag)

    except ValueError as e:
        logger.error("Job %s: Invalid message: %s", job_id, e)
        # Reject the message, don't requeue malformed messages
        channel.basic_nack(delivery_tag=method.delivery_tag, requeue=False)
    except Exception as e:
        logger.exception("Job %s: Unexpected error: %s", job_id, e)
        channel.basic_nack(delivery_tag=method.delivery_tag, requeue=False)


def create_connection(host="localhost", port=5672, username="guest", password="guest",
                      virtual_host="/", use_ssl=False):
    """Create a RabbitMQ connection with optional TLS."""
    credentials = pika.PlainCredentials(username, password)

    ssl_options = None
    if use_ssl:
        import ssl
        context = ssl.create_default_context()
        ssl_options = pika.SSLOptions(context, host)

    parameters = pika.ConnectionParameters(
        host=host,
        port=port,
        virtual_host=virtual_host,
        credentials=credentials,
        ssl_options=ssl_options,
        heartbeat=600,
        blocked_connection_timeout=300,
    )

    return pika.BlockingConnection(parameters)


def main():
    """Main entry point for the job consumer."""
    rabbitmq_host = os.environ.get("RABBITMQ_HOST", "localhost")
    rabbitmq_port = int(os.environ.get("RABBITMQ_PORT", "5672"))
    rabbitmq_user = os.environ.get("RABBITMQ_USER", "guest")
    rabbitmq_pass = os.environ.get("RABBITMQ_PASS", "guest")
    rabbitmq_vhost = os.environ.get("RABBITMQ_VHOST", "/")
    use_ssl = os.environ.get("RABBITMQ_SSL", "false").lower() == "true"
    queue_name = os.environ.get("JOB_QUEUE", "batch_jobs")

    logger.info("Connecting to RabbitMQ at %s:%d", rabbitmq_host, rabbitmq_port)
    logger.info("Allowed commands: %s", list(ALLOWED_COMMANDS.keys()))
    logger.info("Allowed work directories: %s", ALLOWED_WORK_DIRS)

    connection = create_connection(
        host=rabbitmq_host,
        port=rabbitmq_port,
        username=rabbitmq_user,
        password=rabbitmq_pass,
        virtual_host=rabbitmq_vhost,
        use_ssl=use_ssl,
    )

    channel = connection.channel()

    # Declare the queue (durable so it survives broker restarts)
    channel.queue_declare(queue=queue_name, durable=True)

    # Fair dispatch - don't give more than one message to a worker at a time
    channel.basic_qos(prefetch_count=1)

    # Set up the consumer
    channel.basic_consume(queue=queue_name, on_message_callback=on_message)

    logger.info("Waiting for jobs on queue '%s'. Press CTRL+C to exit.", queue_name)

    try:
        channel.start_consuming()
    except KeyboardInterrupt:
        logger.info("Shutting down consumer...")
        channel.stop_consuming()
    finally:
        connection.close()
        logger.info("Connection closed.")


if __name__ == "__main__":
    main()